sql:
SELECT fragment_name
FROM fragmentation_patterns
WHERE fragment_charge = '+1';

SELECT ion_name
FROM ionization_forms
WHERE ion_charge = '+1';

SELECT lipid_name
  FROM lipid_species
  ORDER BY lipid_name ASC;

SELECT ion_mass
FROM lipid_ionization
WHERE ion_intensity > 5000;

SELECT lipid_name
FROM lipid_species
WHERE species_type = 'phospholipids';

SELECT result_value, result_unit
FROM experiment_results
WHERE experiment_id = 1;

SELECT COUNT(*) AS lipid_count
FROM lipid_species
WHERE molecular_weight BETWEEN 500 AND 600;

SELECT lipid_name, molecular_weight
FROM lipid_species
WHERE lipid_id = 1;

SELECT ion_id, MAX(ion_intensity) AS max_intensity
FROM lipid_ionization
WHERE lipid_id = 0;
